INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('A. Enquadramento geral', 'O que é a Academia de Líderes Ubuntu?', '<p>A Academia de Líderes Ubuntu é um projeto de educação não-formal orientado para a capacitação de jovens com elevado potencial de liderança, provenientes de contextos desafiantes ou com disponibilidade e interesse em trabalhar nesses contextos.</p><p>O seu objetivo é formar líderes servidores, capazes de cuidar de si, dos outros e da comunidade, desenvolvendo competências socioemocionais, sentido de responsabilidade, participação cívica e vontade de ser e fazer melhor.</p>', 0);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('A. Enquadramento geral', 'Quais são os principais objetivos da Academia de Líderes Ubuntu?', '<p>A Academia procura contribuir para o desenvolvimento de competências socioemocionais, promovendo o crescimento pessoal, a participação cívica, o sentido de responsabilidade e a capacidade de liderança ao serviço dos outros.</p>', 10);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('A. Enquadramento geral', 'Que resultados se esperam da participação na Academia?', '<p>A participação na Academia procura promover maior consciência de si, reforço da autoconfiança, capacidade de resiliência, empatia, sentido de serviço e disponibilidade para agir positivamente na comunidade.</p><p>Mais do que transmitir conteúdos, a Academia pretende criar uma experiência transformadora, capaz de gerar aprendizagens pessoais, relacionais e comunitárias.</p>', 20);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('B. Filosofia Ubuntu e princípios do método', 'O que significa “Ubuntu” neste contexto?', '<p>Ubuntu é entendido como uma filosofia e uma ética relacional sintetizada na ideia <em>“eu sou porque tu és”</em>. No contexto da Academia, esta visão valoriza a interdependência, a construção de relações, a responsabilidade pelo outro e a pertença a uma comunidade.</p><p>Ser Ubuntu não substitui outras identidades culturais, religiosas, políticas ou pessoais. Pelo contrário, funciona como uma identidade comum que acolhe a diversidade e permite a ação conjunta em torno do cuidado, da liderança servidora e da construção de pontes.</p>', 30);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('B. Filosofia Ubuntu e princípios do método', 'Quais são os pilares da metodologia Ubuntu?', '<p>A metodologia Ubuntu assenta em cinco pilares:</p><ul><li>Autoconhecimento</li><li>Autoconfiança</li><li>Resiliência</li><li>Empatia</li><li>Serviço</li></ul><p>Estes pilares estruturam o percurso formativo e ajudam os participantes a desenvolver competências pessoais, relacionais e comunitárias.</p>', 40);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('B. Filosofia Ubuntu e princípios do método', 'Quais são os eixos transversais da Academia?', '<p>Para além dos cinco pilares, a Academia é orientada por três eixos transversais:</p><ul><li>Ética do cuidado</li><li>Liderança servidora</li><li>Construção de pontes</li></ul><p>Estes eixos dão sentido à experiência Ubuntu e ajudam a orientar a ação dos participantes para uma liderança mais humana, relacional e comprometida com os outros.</p>', 50);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('B. Filosofia Ubuntu e princípios do método', 'O que significa ser um líder servidor?', '<p>Ser líder servidor significa compreender a liderança como serviço. Na metodologia Ubuntu, liderar não é exercer poder sobre os outros, mas cuidar, escutar, criar pontes, inspirar e contribuir para o bem comum.</p><p>A liderança servidora está ligada à responsabilidade pessoal, à atenção ao outro e à vontade de colocar os próprios talentos ao serviço da comunidade.</p>', 60);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('B. Filosofia Ubuntu e princípios do método', 'A Academia de Líderes Ubuntu é uma formação teórica?', '<p>Não apenas. Embora tenha fundamentos pedagógicos e conceitos estruturantes, a Academia é sobretudo uma experiência de aprendizagem.</p><p>O método valoriza a experiência, a reflexão, a interação, a expressão artística, a partilha e a ação. Os participantes são convidados a viver um percurso pessoal e coletivo, e não apenas a receber informação.</p>', 70);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('C. Participantes', 'Quem pode participar na Academia de Líderes Ubuntu?', '<p>A Academia destina-se a jovens com potencial de liderança, provenientes de contextos desafiantes ou com interesse e disponibilidade para trabalhar nesses contextos.</p><p>Em contexto escolar, pode ser desenvolvida com estudantes, envolvendo também educadores e outros atores da comunidade educativa.</p>', 80);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('C. Participantes', 'A Academia é apenas para jovens com dificuldades?', '<p>Não. A Academia não se dirige apenas a jovens com dificuldades. Os documentos indicam que pode envolver jovens com elevado potencial de liderança, jovens provenientes de contextos desafiantes ou jovens que queiram trabalhar nesses contextos.</p><p>O método pode ser relevante para perfis variados, desde que exista abertura para a experiência, disponibilidade para a reflexão e vontade de crescer na relação consigo, com os outros e com a comunidade.</p>', 90);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('C. Participantes', 'Como devem ser selecionados os participantes?', '<p>A seleção dos participantes deve ter em conta o potencial de liderança, a motivação, a maturidade e a disponibilidade para viver uma experiência exigente de aprendizagem pessoal e coletiva.</p><p>Em contexto escolar, a seleção pode ser definida pela própria escola, de acordo com os seus objetivos educativos e com a estratégia que pretende implementar.</p>', 100);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('C. Participantes', 'Os participantes devem vir da mesma turma ou de grupos diferentes?', '<p>As duas possibilidades são válidas. Quando os participantes vêm de grupos ou turmas diferentes, a Academia pode criar laços entre pessoas que talvez não se conhecessem e espalhar o “espírito Ubuntu” por mais contextos.</p><p>Quando pertencem ao mesmo grupo ou turma, podem criar-se laços fortes de cuidado mútuo e um capital relacional importante para projetos futuros.</p>', 110);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('D. Semana Ubuntu', 'O que é uma Semana Ubuntu?', '<p>A Semana Ubuntu é a experiência intensiva da Academia, idealmente organizada em cinco dias consecutivos. Cada dia corresponde a um seminário temático, com uma sequência própria e intencional.</p><p>A Semana Ubuntu trabalha os cinco pilares do método através de atividades, dinâmicas, reflexão pessoal, partilha em grupo, recursos artísticos, filmes, música, histórias e momentos de aprendizagem experiencial.</p>', 120);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('D. Semana Ubuntu', 'Quais são os cinco seminários da Semana Ubuntu?', '<p>A estrutura-tipo da Academia inclui cinco seminários:</p><ol><li>Liderar como Mandela</li><li>Construir Pontes</li><li>Vencer Obstáculos</li><li>Vidas Ubuntu</li><li>I have a dream</li></ol><p>Esta sequência corresponde a um percurso pedagógico progressivo, que começa pela introdução ao conceito Ubuntu e à liderança servidora, aprofunda a reflexão pessoal e relacional, e termina com o sonho, o serviço e o compromisso com a ação.</p>', 130);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('D. Semana Ubuntu', 'Porque é que a ordem dos seminários é importante?', '<p>A ordem dos seminários corresponde a uma lógica pedagógica inspirada na chamada “Teoria do U”. O percurso começa com uma entrada mais acolhedora e introdutória, aprofunda progressivamente a reflexão pessoal e emocional, e termina com uma orientação para o futuro, o sonho e o serviço.</p><p>Por isso, a sequência não deve ser alterada nem substituída por atividades avulsas. A força da metodologia está no percurso completo e na forma como cada etapa prepara a seguinte.</p>', 140);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('D. Semana Ubuntu', 'Porque é que a Semana Ubuntu tem dias inteiros de formação?', '<p>O método Ubuntu aposta numa lógica de imersão pedagógica. Os seminários têm, idealmente, a duração de um dia completo, permitindo aos participantes sair do ritmo habitual e dedicar-se de forma intensa à experiência.</p><p>Esta imersão procura gerar foco, disponibilidade, abertura à experiência e uma aprendizagem mais transformadora.</p>', 150);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('D. Semana Ubuntu', 'Que tipo de atividades acontecem na Semana Ubuntu?', '<p>As atividades podem incluir dinâmicas de grupo, jogos pedagógicos, momentos de reflexão pessoal, diálogos em pequenos grupos, filmes, música, contos, convidados, exercícios criativos e outras metodologias de educação não-formal.</p><p>Cada atividade deve estar integrada na lógica global da Semana Ubuntu e contribuir para os objetivos pedagógicos do percurso.</p>', 160);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('D. Semana Ubuntu', 'A Semana Ubuntu pode ser feita através de atividades soltas?', '<p>Não é essa a lógica do método. Os documentos sublinham que a metodologia Ubuntu não deve ser desmembrada em atividades avulsas, realizadas ao acaso ou sem sequência pedagógica.</p><p>A Semana Ubuntu é pensada como um caminho progressivo, em que cada momento prepara o seguinte e contribui para a experiência global.</p>', 170);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('E. Metodologia pedagógica', 'A Academia de Líderes Ubuntu é educação formal ou não-formal?', '<p>A metodologia Ubuntu situa-se no domínio da educação não-formal, embora possa acontecer em contextos formais, como a escola.</p><p>Isto significa que não funciona como uma aula tradicional. A relação entre formadores e participantes é menos hierárquica, mais colaborativa e centrada no participante. A aprendizagem acontece pela experiência, pela reflexão, pela interação com os outros e pela construção coletiva de sentido.</p>', 180);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('E. Metodologia pedagógica', 'Que metodologia pedagógica é utilizada?', '<p>O método Ubuntu é uma abordagem estruturada, centrada no participante, em que o formador assume sobretudo o papel de facilitador.</p><p>A metodologia é influenciada pela aprendizagem socio-construtivista, pela educação não-formal e pelo ciclo de aprendizagem experiencial de Kolb. Cada dinâmica deve permitir viver uma experiência, refletir sobre ela, retirar aprendizagens e perceber como aplicá-las na vida.</p>', 190);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('E. Metodologia pedagógica', 'O que é o ciclo de aprendizagem experiencial de Kolb e como se aplica à Academia?', '<p>O ciclo de Kolb organiza a aprendizagem em quatro momentos: experiência concreta, observação reflexiva, conceptualização abstrata e experimentação ativa.</p><p>Na metodologia Ubuntu, as dinâmicas devem permitir que os participantes vivam algo, reflitam sobre o que sentiram e perceberam, retirem aprendizagens e identifiquem formas de agir a partir dessas aprendizagens.</p>', 200);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('E. Metodologia pedagógica', 'Qual é o papel da experiência na aprendizagem Ubuntu?', '<p>A experiência é central. A metodologia Ubuntu parte da ideia de que a aprendizagem não acontece apenas pela transmissão de conteúdos, mas pela vivência, pela reflexão e pela transformação da experiência em aprendizagem.</p><p>Os participantes são convidados a envolver-se ativamente, a refletir sobre o que viveram e a ligar essas aprendizagens à sua própria vida.</p>', 210);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('E. Metodologia pedagógica', 'As dinâmicas da Semana Ubuntu podem ser alteradas livremente?', '<p>Não. Os planos de sessão têm uma sequência, um ritmo e uma intencionalidade pedagógica próprios. O método está aberto a novas contribuições, mas estas devem ser estudadas, testadas e avaliadas antes de serem integradas.</p><p>A fidelidade à metodologia é importante para proteger a coerência e o impacto da experiência.</p>', 220);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('E. Metodologia pedagógica', 'Porque é que não se revelam antecipadamente todas as dinâmicas aos participantes?', '<p>A metodologia Ubuntu valoriza a surpresa. A não antecipação das dinâmicas ajuda a manter a curiosidade e evita que os participantes criem preconceitos ou expectativas que possam reduzir o impacto da experiência.</p><p>Esta lógica contribui para que cada participante viva o percurso com abertura e presença.</p>', 230);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('F. Arte, espaço e ambiente de aprendizagem', 'Que papel têm a arte, a música e os filmes na Academia?', '<p>A arte é usada como método de aprendizagem. A metodologia recorre a filmes, documentários, literatura, contos, biografias, teatro, role play, música e desenho.</p><p>A música tem um papel central no ritmo da formação, ajudando a ligar momentos, criar ambiente e marcar o tom de cada dinâmica — reflexivo, enérgico ou celebrativo. O desenho e outros recursos expressivos são usados para estimular a criatividade, a imaginação, a reflexão e a expressão das aprendizagens.</p>', 240);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('F. Arte, espaço e ambiente de aprendizagem', 'Como deve ser o espaço onde decorre a Semana Ubuntu?', '<p>O espaço deve ser amplo, flexível e, idealmente, diferente da sala de aula habitual. Deve permitir que o grupo se sente em círculo, que todos se vejam e estejam à mesma distância, e que haja espaço para trabalhos de grupo, reflexão e dinâmicas.</p><p>Também deve ter boas condições de projeção e som, uma vez que os filmes e outros recursos audiovisuais fazem parte da metodologia.</p>', 250);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('F. Arte, espaço e ambiente de aprendizagem', 'Porque se trabalha em círculo?', '<p>O círculo é um símbolo importante da Academia de Líderes Ubuntu. Representa proximidade, igualdade, horizontalidade e cuidado mútuo.</p><p>Trabalhar em círculo permite que todos possam ver e ser vistos, favorecendo a relação, a participação e o ambiente de confiança necessário à metodologia.</p>', 260);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('F. Arte, espaço e ambiente de aprendizagem', 'Porque é que o acolhimento é tão importante?', '<p>O acolhimento é considerado um momento-chave da Academia. Receber cada participante com sorriso, alegria e atenção genuína ajuda a criar uma atmosfera positiva, segura e de pertença.</p><p>Este ambiente de confiança é essencial para que os participantes se predisponham a viver a experiência e a envolver-se nas dinâmicas propostas.</p>', 270);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('G. Formadores e educadores', 'Qual é o papel dos formadores na Academia?', '<p>Os formadores devem atuar como facilitadores, animadores e guias do processo de aprendizagem. Devem criar um ambiente seguro, acolhedor e exigente, promovendo relações pedagógicas positivas e construtivas.</p><p>O formador Ubuntu deve inspirar, apoiar, entusiasmar e estar atento aos participantes, sendo intérprete fiel da essência Ubuntu e da liderança servidora.</p>', 280);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('G. Formadores e educadores', 'Que competências devem ter os formadores Ubuntu?', '<p>Os formadores Ubuntu devem ter fortes competências relacionais, capacidade de comunicação, sensibilidade pedagógica, bom senso, atenção aos participantes e capacidade de criar um clima de confiança.</p><p>Devem também ser capazes de gerir o ritmo da sessão, apoiar o grupo, cuidar da logística e manter fidelidade à intencionalidade pedagógica do método.</p>', 290);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('G. Formadores e educadores', 'Qual é a importância da equipa de formação?', '<p>A equipa de formação é essencial para garantir a qualidade da experiência. Deve trabalhar de forma articulada, preparar cuidadosamente as sessões, distribuir responsabilidades e assegurar que cada momento da Semana Ubuntu cumpre a sua função pedagógica.</p><p>A coerência da equipa ajuda a criar segurança, ritmo e confiança no grupo.</p>', 300);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('H. Clube Ubuntu e continuidade', 'O que é o Clube Ubuntu?', '<p>O Clube Ubuntu é uma estrutura de continuidade da experiência da Semana Ubuntu. Permite prolongar aprendizagens, relações, projetos e ações ao longo do tempo.</p><p>Pode envolver participantes das Academias Ubuntu, formadores e outros membros da comunidade educativa ou institucional.</p>', 310);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('H. Clube Ubuntu e continuidade', 'Qual é a relação entre a Semana Ubuntu e o Clube Ubuntu?', '<p>A Semana Ubuntu é a experiência intensiva inicial. O Clube Ubuntu prolonga essa experiência, permitindo que os participantes continuem a desenvolver competências, relações e iniciativas inspiradas na metodologia Ubuntu.</p><p>A lógica experiencial deve continuar presente: viver, refletir, aprender e agir.</p>', 320);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('H. Clube Ubuntu e continuidade', 'Que tipo de atividades pode desenvolver um Clube Ubuntu?', '<p>Um Clube Ubuntu pode desenvolver atividades regulares, desafios, iniciativas comunitárias, ações de serviço, momentos de reflexão, projetos de construção de pontes e eventos que envolvam a comunidade.</p><p>As atividades devem manter ligação aos pilares e eixos da metodologia Ubuntu.</p>', 330);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('I. Símbolos e identidade Ubuntu', 'Que símbolos fazem parte da Academia de Líderes Ubuntu?', '<p>O método Ubuntu tem um sistema simbólico próprio. Entre os símbolos referidos nos documentos estão a identidade “Ubuntu”, o número 466/64 associado a Nelson Mandela, a mão aberta e os cinco pilares, o círculo, as pontes e os construtores de pontes, os modelos de referência e as frases inspiradoras.</p><p>Estes símbolos ajudam a gerar identidade, pertença e inspiração para a ação.</p>', 340);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('I. Símbolos e identidade Ubuntu', 'O que significa o símbolo 466/64?', '<p>466/64 era o número de prisioneiro de Nelson Mandela em Robben Island. Na Academia, este símbolo recorda a capacidade de enfrentar adversidades, preservar a humanidade e transformar experiências difíceis em compromisso com os outros.</p>', 350);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('I. Símbolos e identidade Ubuntu', 'O que representa a mão aberta?', '<p>A mão aberta representa ação, interdependência, colaboração, solidariedade, transparência e ausência de agressividade.</p><p>Os cinco dedos remetem para os cinco pilares do método Ubuntu: autoconhecimento, autoconfiança, resiliência, empatia e serviço.</p>', 360);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('I. Símbolos e identidade Ubuntu', 'O que representam as pontes na metodologia Ubuntu?', '<p>As pontes simbolizam a capacidade de aproximar pessoas, grupos, histórias e realidades diferentes. Ser Ubuntu implica ser construtor de pontes, criando relações onde há distância, separação ou desconfiança.</p><p>A construção de pontes é, por isso, um dos eixos centrais da Academia.</p>', 370);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('I. Símbolos e identidade Ubuntu', 'Porque são importantes os modelos de referência?', '<p>Os modelos de referência ajudam a inspirar os participantes, mostrando vidas marcadas pela coragem, pelo serviço, pela resiliência e pela construção de pontes.</p><p>Na metodologia Ubuntu, figuras como Nelson Mandela e Martin Luther King são usadas como referências para refletir sobre liderança, sonho, superação e compromisso com os outros.</p>', 380);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('J. Funcionamento em diferentes contextos', 'A Academia de Líderes Ubuntu pode acontecer em contexto escolar?', '<p>Sim. Embora seja uma metodologia de educação não-formal, a Academia pode acontecer em contextos formais, como a escola.</p><p>Nesses casos, a metodologia mantém a sua identidade própria: aprendizagem experiencial, centralidade do participante, relação de confiança, trabalho em círculo, dinâmicas participativas e foco nas competências socioemocionais.</p>', 390);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('J. Funcionamento em diferentes contextos', 'A Academia pode acontecer fora da escola?', '<p>Sim. O método Ubuntu pode ser desenvolvido em diferentes contextos educativos e comunitários, desde que sejam respeitados os princípios, a estrutura e a intencionalidade pedagógica da metodologia.</p><p>O espaço escolhido deve favorecer a imersão, a participação, a confiança e a relação entre os participantes.</p>', 400);
INSERT INTO public.faqs (category, question, answer, sort_order) VALUES ('J. Funcionamento em diferentes contextos', 'O que deve ser garantido para uma boa implementação da Academia?', '<p>Uma boa implementação deve garantir:</p><ul><li>Fidelidade aos princípios e pilares Ubuntu</li><li>Equipa de formação preparada e alinhada</li><li>Ambiente seguro e acolhedor</li><li>Espaço adequado à metodologia</li><li>Respeito pela sequência pedagógica</li><li>Ritmo equilibrado entre intensidade e cuidado</li><li>Participação ativa dos participantes</li><li>Continuidade da experiência após a Semana Ubuntu</li></ul><p>A qualidade da Academia depende tanto da estrutura metodológica como da forma como ela é vivida e facilitada.</p>', 410);